import java.io.*;

public class CommandInjectionSecure {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter a file name: ");
        String fileName = reader.readLine();

        // Validate the fileName input to prevent command injection
        if (!fileName.matches("[a-zA-Z0-9_]+\\.txt")) {
            System.out.println("Invalid file name. Only alphanumeric characters and underscores are allowed with .txt extension.");
            return;
        }

        // Construct the command using ProcessBuilder to ensure proper escaping
        ProcessBuilder processBuilder = new ProcessBuilder("cat", fileName);
        Process process = processBuilder.start();

        BufferedReader processOutputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));

        String line;
        while ((line = processOutputReader.readLine()) != null) {
            System.out.println(line);
        }

        process.waitFor();
    }
}

